export const getListReviewsUrl = (scriptId: number) => {
  return `/api/scripts/${scriptId}/reviews`;
};

export const listReviews = async (
  scriptId: number,
  options?: RequestInit,
): Promise<Review[]> => {
  return customFetch<Review[]>(getListReviewsUrl(scriptId), {
    ...options,
    method: "GET",
  });
};

export const getListReviewsQueryKey = (scriptId: number) => {
  return [`/api/scripts/${scriptId}/reviews`] as const;
};

export const getListReviewsQueryOptions = <
  TData = Awaited<ReturnType<typeof listReviews>>,
  TError = ErrorType<unknown>,
>(
  scriptId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listReviews>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListReviewsQueryKey(scriptId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listReviews>>> = ({
    signal,
  }) => listReviews(scriptId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!scriptId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listReviews>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListReviewsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listReviews>>
>;
export type ListReviewsQueryError = ErrorType<unknown>;

/**
 * @summary List reviews for a script
 */

export function useListReviews<
  TData = Awaited<ReturnType<typeof listReviews>>,
  TError = ErrorType<unknown>,
>(
  scriptId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listReviews>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListReviewsQueryOptions(scriptId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Post a review
 */
export const getCreateReviewUrl = (scriptId: number) => {
  return `/api/scripts/${scriptId}/reviews`;
};

export const createReview = async (
  scriptId: number,
  createReviewRequest: CreateReviewRequest,
  options?: RequestInit,
): Promise<Review> => {
  return customFetch<Review>(getCreateReviewUrl(scriptId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createReviewRequest),
  });
};

export const getCreateReviewMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createReview>>,
    TError,
    { scriptId: number; data: BodyType<CreateReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createReview>>,
  TError,
  { scriptId: number; data: BodyType<CreateReviewRequest> },
  TContext
> => {
  const mutationKey = ["createReview"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createReview>>,
    { scriptId: number; data: BodyType<CreateReviewRequest> }
  > = (props) => {
    const { scriptId, data } = props ?? {};

    return createReview(scriptId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateReviewMutationResult = NonNullable<
  Awaited<ReturnType<typeof createReview>>
>;
export type CreateReviewMutationBody = BodyType<CreateReviewRequest>;
export type CreateReviewMutationError = ErrorType<unknown>;

/**
 * @summary Post a review
 */
export const useCreateReview = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createReview>>,
    TError,
    { scriptId: number; data: BodyType<CreateReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createReview>>,
  TError,
  { scriptId: number; data: BodyType<CreateReviewRequest> },
  TContext
> => {
  return useMutation(getCreateReviewMutationOptions(options));
};

